from dataclasses import dataclass, field
from typing import Optional

@dataclass
class AIDecisionCard:
    """Artefact produced for every AI Decision node in the event storm."""

    # Identity
    event_name: str            # e.g. "ResponseGenerated"
    feature_name: str
    bounded_context: str       # Which service/team owns this decision

    # Model contract
    model_id: Optional[str]    # None if TBD at workshop time
    input_schema: str          # Informal description or JSON Schema reference
    output_schema: str         # Expected format; must be machine-checkable post-launch
    max_input_tokens: int      # Prompt + context budget
    max_output_tokens: int     # Upper bound on response length

    # Quality bar
    latency_p95_ms: int        # P95 latency SLA
    primary_eval_metric: str   # e.g. "BLEU-4", "accuracy@1", "G-Eval score", "human CSAT"
    eval_threshold: float      # Minimum acceptable score on primary metric
    eval_harness: Optional[str]= None  # Name of the eval suite that measures this

    # Risk
    is_non_deterministic: bool = True   # Almost always True for LLM decisions
    consistency_policy: str = ""        # e.g. "Retry up to 3× with T=0 on schema violation"
    fallback_behaviour: str = ""        # What happens if model is unavailable or fails guardrail

    # Governance
    must_log_input: bool = False
    must_log_output: bool = False
    pii_in_input: bool = False
    guardrail_required: bool = False
    guardrail_id: Optional[str] = None  # e.g. "llama-guard-2"

    def is_complete(self) -> bool:
        required = [
            self.event_name, self.feature_name, self.bounded_context,
            self.input_schema, self.output_schema, self.primary_eval_metric,
            self.fallback_behaviour,
        ]
        return all(required)

    def missing_fields(self) -> list[str]:
        checks = {
            "model_id": self.model_id,
            "eval_harness": self.eval_harness,
            "consistency_policy": self.consistency_policy,
        }
        return [k for k, v in checks.items() if not v]

    def markdown(self) -> str:
        return f"""## AI Decision Card: {self.event_name}

**Feature:** {self.feature_name}
**Owner:** {self.bounded_context}
**Model:** {self.model_id or 'TBD'}

### Input Contract
{self.input_schema}
Max tokens: {self.max_input_tokens}

### Output Contract
{self.output_schema}
Max tokens: {self.max_output_tokens}

### Quality Bar
- Latency P95: ≤ {self.latency_p95_ms} ms
- Primary metric: {self.primary_eval_metric} ≥ {self.eval_threshold}
- Eval harness: {self.eval_harness or 'TBD'}

### Risk Controls
- Non-deterministic: {self.is_non_deterministic}
- Consistency policy: {self.consistency_policy or 'TBD'}
- Fallback: {self.fallback_behaviour}
- Guardrail: {self.guardrail_id or 'None'}

### Logging
- Log input: {self.must_log_input}
- Log output: {self.must_log_output}
- Contains PII: {self.pii_in_input}
"""
